// O compilador gera um main() por baixo dos panos
@main
struct MeuAppApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()  // a primeira View do app
        }
    }
}

// App é um protocol com um requisito:
protocol App {
    associatedtype Body: Scene
    var body: Self.Body { get }  // igual ao protocol View, mas retorna Scene
}

// WindowGroup é a Scene mais comum — permite múltiplas janelas no iPadOS/macOS
@main
struct MeuAppApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}

// Outras Scenes úteis:
// DocumentGroup — para apps baseados em documentos
// Settings — painel de configurações no macOS
// MenuBarExtra — ícone na barra de menu do macOS

@main
struct MeuAppApp: App {
    // init roda UMA vez — ideal para configurações globais
    init() {
        // Configurar aparência global de UINavigationBar (interop UIKit)
        UINavigationBar.appearance().largeTitleTextAttributes = [
            .foregroundColor: UIColor.systemBlue
        ]
    }

    var body: some Scene {
        WindowGroup {
            ContentView()
                .modelContainer(for: Tarefa.self)  // SwiftData
        }
    }
}

// ERRADO — trabalho pesado no body:
struct MinhaView: View {
    var body: some View {
        let dados = carregarDoDiscoDeSincronamente()  // bloqueia o body!
        return Text(dados)
    }
}

// CORRETO — body descreve a UI, trabalho pesado fica em outros lugares:
struct MinhaView: View {
    @State private var dados = ""

    var body: some View {
        Text(dados)  // apenas descreve o layout
            .task {
                dados = await carregarDaRede()  // assíncrono, fora do body
            }
    }
}

struct ListaDeTarefas: View {
    @State private var tarefas: [Tarefa] = []

    var body: some View {
        List(tarefas) { tarefa in
            Text(tarefa.titulo)
        }
        .onAppear {
            // Cuidado: pode ser chamado mais de uma vez
            print("Lista apareceu")
            carregarTarefas()
        }
        .onDisappear {
            print("Lista sumiu da tela")
            cancelarBuscas()
        }
    }
}

struct PerfilView: View {
    let usuarioId: UUID
    @State private var perfil: Perfil?

    var body: some View {
        Group {
            if let perfil {
                Text(perfil.nome)
            } else {
                ProgressView()
            }
        }
        // task cancela a busca automaticamente se o usuário sair:
        .task {
            do {
                perfil = try await PerfilService.buscar(id: usuarioId)
            } catch {
                print("Erro: \(error)")
            }
        }
    }
}

// task com id — refaz a busca quando o id muda:
.task(id: filtro) {
    resultados = await buscar(filtro: filtro)
}

@main
struct MeuAppApp: App {
    @Environment(\.scenePhase) private var scenePhase

    var body: some Scene {
        WindowGroup {
            ContentView()
        }
        .onChange(of: scenePhase) { _, novaFase in
            switch novaFase {
            case .active:
                print("App ativo — usuário está interagindo")
            case .inactive:
                print("App inativo — em transição")
            case .background:
                print("App em segundo plano — salvar dados")
            @unknown default:
                break
            }
        }
    }
}

// Toda vez que contador muda, o SwiftUI:
// 1. Chama body de novo → nova View tree (efêmera)
// 2. Compara com a Render tree anterior
// 3. Atualiza apenas o que mudou
// 4. Descarta a View tree
struct ContadorView: View {
    @State private var contador = 0

    var body: some View {
        Button("\(contador)") {  // body é chamado novamente a cada toque
            contador += 1
        }
    }
}

// Identidade DIFERENTE — dois nodos distintos no View tree:
// Quando ativo muda, o @State do Text é reiniciado!
HStack {
    if ativo {
        Text("Ativo")   // nodo 1.ifBranch — identidade separada
            .bold()
    } else {
        Text("Inativo")  // nodo 1.elseBranch — identidade separada
    }
}

// Identidade ESTÁVEL — mesmo nodo, só o conteúdo muda:
// @State do Text persiste entre as mudanças
HStack {
    Text(ativo ? "Ativo" : "Inativo")  // sempre o mesmo nodo na posição 0
        .bold(ativo)                    // propriedade muda, identidade não
}

// ANTI-PADRÃO — applyIf cria ConditionalContent:
// Quando 'destacado' muda, a identidade do Text muda
extension View {
    @ViewBuilder
    func applyIf<V: View>(_ condition: Bool, transform: (Self) -> V) -> some View {
        if condition {
            transform(self)  // ramo ifBranch
        } else {
            self             // ramo elseBranch
        }
    }
}

Text("Olá")
    .applyIf(destacado) { $0.background(.yellow) }  // identidade instável!

// CORRETO — identidade estável, só o valor muda:
Text("Olá")
    .background(destacado ? Color.yellow : Color.clear)  // mesmo nodo sempre

// .id() explícito — força recriação completa quando o id muda:
struct FormularioView: View {
    @State private var versaoFormulario = UUID()

    var body: some View {
        VStack {
            CamposFormulario()
                .id(versaoFormulario)  // nova UUID = View nova = @State resetado

            Button("Limpar") {
                versaoFormulario = UUID()  // reseta TUDO no formulário
            }
        }
    }
}

// Em ForEach — identidade explícita por item:
ForEach(tarefas) { tarefa in        // usa tarefa.id como identidade explícita
    TarefaRow(tarefa: tarefa)
}

ForEach(itens, id: \.nome) { item in  // usa nome como identidade
    Text(item.nome)
}

