// @State vive no nodo da Render tree:
struct Contador: View {
    @State private var valor = 0  // só é 0 quando o nodo é CRIADO

    // Depois que o nodo existe, o valor persiste:
    // Se o pai recrear Contador, mas o nodo continua existindo,
    // valor NÃO volta para 0
    var body: some View {
        Button("\(valor)") { valor += 1 }
    }
}

// PROBLEMA: passar @State via init não funciona como esperado
struct Contador: View {
    @State private var valor: Int

    // Só muda o initialValue — não afeta o valor atual no nodo
    init(inicialWith v: Int = 0) {
        _valor = State(initialValue: v)
    }

    // Se o pai mudar 'v' depois que o nodo existe, o botão não atualiza!
}

// Preview básico — instância direta da View:
#Preview {
    ContentView()
}

// Com nome — aparece no canvas como aba:
#Preview("Modo escuro") {
    ContentView()
        .preferredColorScheme(.dark)
}

// Múltiplos previews no mesmo arquivo:
#Preview("iPhone") {
    MinhaView()
}

#Preview("iPad") {
    MinhaView()
        .previewDevice("iPad Pro 11-inch (M4)")
}

// Dados de preview junto ao modelo:
extension Tarefa {
    static var preview: Tarefa {
        Tarefa(titulo: "Revisar PR", concluida: false)
    }

    static var previews: [Tarefa] {
        [
            Tarefa(titulo: "Revisar PR", concluida: false),
            Tarefa(titulo: "Escrever testes", concluida: true),
            Tarefa(titulo: "Um título muito longo que vai quebrar o layout de formas interessantes", concluida: false)
        ]
    }
}

// Preview usando os dados de exemplo:
#Preview("Lista cheia") {
    ListaDeTarefasView(tarefas: Tarefa.previews)
}

#Preview("Lista vazia") {
    ListaDeTarefasView(tarefas: [])
}

// DIFÍCIL de testar em Preview — acessa dados globais:
struct PerfilView: View {
    var body: some View {
        Text(SessaoAtual.shared.usuario.nome)  // Preview não tem SessaoAtual
    }
}

// FÁCIL de testar em Preview — dados são parâmetro:
struct PerfilView: View {
    let usuario: Usuario  // recebe por injeção

    var body: some View {
        Text(usuario.nome)
    }
}

#Preview {
    PerfilView(usuario: Usuario.preview)  // funciona no canvas
}
